/**
 * PressVideo — Lazy iframe injector + YouTube IFrame API.
 * Vanilla JS. No jQuery.
 */
(function(){'use strict';const CANVAS_ID='pv-canvas';const AUTOPLAY_MS=3000;let canvas,holder,spinner;let spinnerTimer=null;let ytPlayer=null;let ytApiReady=!!(window.YT&&window.YT.Player);let ytApiQueue=[];(function loadYtApi(){if(ytApiReady||document.getElementById('pv-yt-api'))return;var prev=window.onYouTubeIframeAPIReady;window.onYouTubeIframeAPIReady=function(){if(typeof prev==='function')prev();ytApiReady=true;ytApiQueue.forEach(function(fn){fn()});ytApiQueue=[]};var s=document.createElement('script');s.id='pv-yt-api';s.src='https://www.youtube.com/iframe_api';document.head.appendChild(s)}());function whenYtReady(fn){ytApiReady?fn():ytApiQueue.push(fn)}function init(){canvas=document.getElementById(CANVAS_ID);if(!canvas)return;holder=canvas.querySelector('.pv-iframe-holder');spinner=canvas.querySelector('.pv-spinner');canvas.addEventListener('pv:opened',onOpen);canvas.addEventListener('pv:closed',onClose)}function onOpen(){if(!holder)return;const embedUrl=holder.dataset.embedUrl;if(!embedUrl||holder.dataset.loaded)return;showSpinner();// Extract video ID from embed URL
const url=new URL(embedUrl.replace('watch?v=','embed/'));const ytId=url.pathname.split('/').pop().split('?')[0];if(!ytId){hideSpinner();return}if(ytPlayer){try{ytPlayer.destroy()}catch(e){}ytPlayer=null}// Create a div for YT.Player to mount into — this is more reliable than wrapping an existing iframe
const div=document.createElement('div');div.id='pv-yt-player';div.style.cssText='width:100%;height:100%';holder.innerHTML='';holder.appendChild(div);spinnerTimer=setTimeout(function(){hideSpinner();holder.dataset.loaded='1'},AUTOPLAY_MS);whenYtReady(function(){const el=document.getElementById('pv-yt-player');if(!el||!el.isConnected)return;try{ytPlayer=new YT.Player('pv-yt-player',{videoId:ytId,width:'100%',height:'100%',playerVars:{autoplay:1,rel:0,modestbranding:1,playsinline:1},events:{onReady:function(){clearTimeout(spinnerTimer);hideSpinner();holder.dataset.loaded='1';const iframe=holder.querySelector('iframe');if(iframe){iframe.style.width='100%';iframe.style.height='100%';iframe.style.border='none';iframe.style.display='block';iframe.title=canvas.querySelector('.pv-title')?.textContent||'Video'}},onStateChange:function(e){if(e.data===YT.PlayerState.ENDED){canvas.dispatchEvent(new CustomEvent('pv:video-ended',{bubbles:false}))}}}})}catch(err){clearTimeout(spinnerTimer);hideSpinner()}});canvas.dispatchEvent(new CustomEvent('pv:iframe-ready',{bubbles:false,detail:{youtubeId:ytId}}))}function onClose(){if(!holder)return;clearTimeout(spinnerTimer);if(ytPlayer){try{ytPlayer.destroy()}catch(e){}ytPlayer=null}holder.innerHTML='';delete holder.dataset.loaded;hideSpinner()}function showSpinner(){if(spinner){spinner.removeAttribute('hidden');spinner.style.display=''}}function hideSpinner(){if(spinner){spinner.style.display='none'}}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',init)}else{init()}}());
